---@class LGameRunMode
local LGameRunMode = LxClass("LGameRunMode", nil)
LGameRunMode._runMode = 0

-----------------------------------------------------------------
LGameRunMode.IDLE = 0
LGameRunMode.LOADING_SCENE = 1
LGameRunMode.PREPARE_SCENE = 2

LGameRunMode.LOADING_MAP = 21
-----------------------------------------------------------------

function LGameRunMode.ClearRunMode()
	LGameRunMode._runMode = LGameRunMode.IDLE
end

function LGameRunMode.IsRunMode(mode)
	return LGameRunMode._runMode == mode
end

function LGameRunMode.SetRunMode(mode)
	LGameRunMode._runMode = mode
end

function LGameRunMode.IsLoading()
	return LGameRunMode._runMode == LGameRunMode.LOADING_SCENE or LGameRunMode._runMode == LGameRunMode.PREPARE_SCENE
end

